import{_ as o,o as t,c as a,a2 as r}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Security Model","description":"","frontmatter":{},"headers":[],"relativePath":"reference/security-model.md","filePath":"reference/security-model.md","lastUpdated":null}'),i={name:"reference/security-model.md"};function n(d,e,l,s,c,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="security-model" tabindex="-1">Security Model <a class="header-anchor" href="#security-model" aria-label="Permalink to &quot;Security Model&quot;">​</a></h1><p>Autofac&#39;s security model is built around autonomy without blind trust. Agents can act, but every meaningful action crosses a governance boundary and leaves evidence.</p><h2 id="layers-of-control" tabindex="-1">Layers of control <a class="header-anchor" href="#layers-of-control" aria-label="Permalink to &quot;Layers of control&quot;">​</a></h2><ol><li>BPMN process boundary.</li><li>Policy-enforced Tool Gateway.</li><li>Agent permissions and allowed/denied tool lists.</li><li>Sandboxed execution.</li><li>Human approval gates.</li><li>Evidence and audit records.</li></ol><h2 id="process-boundary" tabindex="-1">Process boundary <a class="header-anchor" href="#process-boundary" aria-label="Permalink to &quot;Process boundary&quot;">​</a></h2><p>The workflow defines what work may happen and in what order. Agent behavior is attached to versioned BPMN tasks, not left as an open-ended chat session.</p><h2 id="tool-gateway" tabindex="-1">Tool Gateway <a class="header-anchor" href="#tool-gateway" aria-label="Permalink to &quot;Tool Gateway&quot;">​</a></h2><p>Every tool or connector call is brokered. The gateway evaluates policy before execution and records the invocation. Decisions can be:</p><table tabindex="0"><thead><tr><th>Decision</th><th>Meaning</th></tr></thead><tbody><tr><td><code>allow</code></td><td>The action can run.</td></tr><tr><td><code>escalate</code></td><td>The action requires human review or a modeled approval path.</td></tr><tr><td><code>reject</code></td><td>The action is blocked.</td></tr></tbody></table><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p>Each agent task can carry:</p><ul><li><code>permissionLevel</code></li><li><code>allowedTools</code></li><li><code>deniedTools</code></li><li><code>purposeType</code></li><li><code>policyTag</code></li><li><code>sandboxProfile</code></li></ul><p>The gateway denies anything outside the task&#39;s granted surface.</p><h2 id="sandbox-network-policy" tabindex="-1">Sandbox network policy <a class="header-anchor" href="#sandbox-network-policy" aria-label="Permalink to &quot;Sandbox network policy&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Profile</th><th>Docker behavior</th></tr></thead><tbody><tr><td><code>offline</code></td><td>No network.</td></tr><tr><td><code>repo-read</code></td><td>Bridge networking unless a stronger provider/proxy enforces egress.</td></tr><tr><td><code>repo-write</code></td><td>Bridge networking unless a stronger provider/proxy enforces egress.</td></tr><tr><td><code>deployment</code></td><td>Bridge networking unless a stronger provider/proxy enforces egress.</td></tr></tbody></table><p>Plain Docker bridge networking does not enforce per-host allow-lists on its own. Use an egress proxy, OpenSandbox, or Kubernetes-backed isolation when host-level network restrictions are required.</p><h2 id="secrets" tabindex="-1">Secrets <a class="header-anchor" href="#secrets" aria-label="Permalink to &quot;Secrets&quot;">​</a></h2><ul><li>Model API keys and connector tokens are read from the secret store or deployment configuration.</li><li>Secret values should be injected only where needed.</li><li>The Settings API returns only secret status, source, and fingerprint.</li><li>Secret rotations are write-only from the browser.</li><li>Prompts are redacted in persisted snapshots, but prompts and run context should never contain secrets.</li></ul><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><p>The API supports JWT auth with role-based policies:</p><ul><li><code>Viewer</code></li><li><code>Operator</code></li><li><code>Approver</code></li><li><code>Admin</code></li></ul><p>Development tokens and development identity are for local use only.</p><h2 id="evidence-pack" tabindex="-1">Evidence pack <a class="header-anchor" href="#evidence-pack" aria-label="Permalink to &quot;Evidence pack&quot;">​</a></h2><p>The evidence pack records:</p><ul><li>redacted prompts</li><li>model usage and cost</li><li>tool invocations</li><li>policy decisions</li><li>sandbox executions</li><li>approvals</li><li>artifacts</li><li>audit log</li><li>BPMN hash</li></ul><p>Use it as the primary artifact for run review, investigation, and compliance records.</p>',26)])])}const y=o(i,[["render",n]]);export{u as __pageData,y as default};
